const unsplash = (idOrTerm, w = 1200) => {
  if (!idOrTerm) return `https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&q=80&w=${w}`;

  // 1. Direct Unsplash ID (handle both photo-XXXX and raw IDs)
  const cleanId = idOrTerm.trim();
  if (cleanId.length >= 10 && !cleanId.includes(" ")) {
    const prefix = cleanId.includes("-") ? "photo-" : "photo-1"; // photo-1 is a safe prefix for most raw IDs
    return `https://images.unsplash.com/photo-${cleanId.replace("photo-", "")}?auto=format&fit=crop&q=80&w=${w}`;
  }

  // 2. High-Precision Keyword Search
  const query = encodeURIComponent(`${idOrTerm},cinematic,travel,high-fidelity`);
  return `https://images.unsplash.com/featured/${w}x${Math.round(w * 0.5625)}/?${query}`;
};

