function AccordionWidget({ title, icon: Icon, iconColor, defaultOpen = false, children }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="rounded-[20px] overflow-hidden transition-all duration-300" style={{ background: '#0F1623', border: '1px solid rgba(255,255,255,0.06)', flexShrink: 0 }}>
      <div className="p-4 flex items-center justify-between cursor-pointer hover:bg-white/[0.02]" onClick={() => setOpen(!open)}>
        <div className="flex items-center gap-3">
          <Icon size={18} style={{ color: iconColor }} />
          <h3 className="text-sm font-bold text-white tracking-wide">{title}</h3>
        </div>
        <motion.div animate={{ rotate: open ? 180 : 0 }} transition={{ duration: 0.2 }}>
          <ChevronDown size={16} className="text-white/40" />
        </motion.div>
      </div>
      <AnimatePresence>
        {open && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="overflow-hidden">
            <div className="px-4 pb-4 pt-1">
              {children}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

