ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬
function MapWidget({ destination, isLight = false }) {
  const [mapUrl, setMapUrl] = useState('');
  const containerRef = useRef(null);

  useEffect(() => {
    let alive = true;
    if (!destination) return;

    fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(destination)}&format=json&limit=1`)
      .then(res => res.json())
      .then(data => {
        if (alive && data && data.length > 0) {
          const { boundingbox, lat, lon } = data[0];
          const [lat1, lat2, lon1, lon2] = boundingbox;
          const padY = Math.max((parseFloat(lat2) - parseFloat(lat1)) * 0.12, 0.08);
          const padX = Math.max((parseFloat(lon2) - parseFloat(lon1)) * 0.12, 0.08);
          const minLon = parseFloat(lon1) - padX;
          const minLat = parseFloat(lat1) - padY;
          const maxLon = parseFloat(lon2) + padX;
          const maxLat = parseFloat(lat2) + padY;
          const url = `https://www.openstreetmap.org/export/embed.html?bbox=${minLon}%2C${minLat}%2C${maxLon}%2C${maxLat}&layer=mapnik&marker=${lat}%2C${lon}`;
          setMapUrl(url);
        } else if (alive) {
          setMapUrl(`https://www.openstreetmap.org/export/embed.html?query=${encodeURIComponent(destination)}&layer=mapnik`);
        }
      })
      .catch(() => {
        if (alive) setMapUrl(`https://www.openstreetmap.org/export/embed.html?query=${encodeURIComponent(destination)}&layer=mapnik`);
      });

    return () => { alive = false; };
  }, [destination]);

  return (
    <div
      ref={containerRef}
      className={cn(
        "mb-3 overflow-hidden rounded-[26px] border shadow-[0_20px_55px_rgba(0,0,0,0.28)] transition-colors duration-500",
        isLight
          ? "border-slate-200/80 bg-[linear-gradient(180deg,rgba(255,255,255,0.96)_0%,rgba(239,246,255,0.94)_100%)] shadow-[0_24px_55px_rgba(148,163,184,0.18)]"
          : "border-white/[0.08] bg-[linear-gradient(180deg,rgba(14,22,36,0.98)_0%,rgba(8,13,24,0.98)_100%)]"
      )}
    >
      <div className={cn("flex items-center justify-between border-b px-4 py-3 transition-colors duration-500", isLight ? "border-slate-200/70" : "border-white/[0.06]")}>
        <div className="min-w-0">
          <p className="text-[9px] font-black uppercase tracking-[0.32em] text-[#38BDF8]">Live Map View</p>
          <p className={cn("mt-1 truncate text-[12px] font-semibold", isLight ? "text-slate-700" : "text-white/78")}>{destination}</p>
        </div>
        <a
          href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(destination)}`}
          target="_blank"
          rel="noreferrer"
          className="inline-flex items-center gap-1.5 rounded-full border border-[#38BDF8]/20 bg-[#38BDF8]/8 px-3 py-1.5 text-[11px] font-semibold text-[#7DD3FC] transition-colors hover:border-[#38BDF8]/35 hover:text-white"
        >
          Open full map <ExternalLink size={12} />
        </a>
      </div>

      <div className={cn("relative h-[248px] overflow-hidden transition-colors duration-500", isLight ? "bg-slate-100" : "bg-[#0d1522]")}>
        <div className={cn("pointer-events-none absolute inset-x-0 top-0 z-[1] h-14", isLight ? "bg-[linear-gradient(180deg,rgba(255,255,255,0.55)_0%,transparent_100%)]" : "bg-[linear-gradient(180deg,rgba(7,12,22,0.35)_0%,transparent_100%)]")} />
        {mapUrl ? (
          <iframe
            src={mapUrl}
            className="absolute inset-0 h-full w-full border-0"
            title={`Map of ${destination}`}
            loading="lazy"
          />
        ) : (
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(56,189,248,0.18),transparent_58%),linear-gradient(180deg,#142033_0%,#0b1321_100%)]" />
        )}
      </div>

      <div className={cn("flex items-center justify-between px-4 py-3 transition-colors duration-500", isLight ? "bg-slate-100/70" : "bg-white/[0.02]")}>
        <div className="flex min-w-0 items-center gap-2">
          <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-[#38BDF8]/10 ring-1 ring-[#38BDF8]/18">
            <MapPin size={13} className="text-[#38BDF8]" strokeWidth={2.5} />
          </div>
          <div className="min-w-0">
            <p className={cn("text-[9px] font-black uppercase tracking-[0.26em]", isLight ? "text-slate-400" : "text-white/28")}>Destination</p>
            <p className={cn("truncate text-[12px] font-semibold", isLight ? "text-slate-700" : "text-white/72")}>{destination}</p>
          </div>
        </div>
        <a
          href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(destination)}`}
          target="_blank"
          rel="noreferrer"
          className={cn(
            "inline-flex items-center gap-1.5 rounded-full border px-3 py-1.5 text-[10px] font-black uppercase tracking-[0.22em] transition-all hover:-translate-y-0.5",
            isLight
              ? "border-emerald-400/50 bg-emerald-50 text-emerald-700 hover:border-emerald-500 hover:bg-emerald-100"
              : "border-emerald-400/25 bg-emerald-400/10 text-emerald-300 hover:border-emerald-300/45 hover:bg-emerald-400/16 hover:text-emerald-200"
          )}
        >
          Explore
          <ChevronRight size={12} />
        </a>
      </div>
    </div>
  );
}

