¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬
function PrayerTimesWidget({ destination, dateStr, dayIdx, onPrev, onNext }) {
  const [times, setTimes] = useState(null);
  const [hijriDate, setHijriDate] = useState('');

  useEffect(() => {
    let alive = true;
    if (!destination) return;

    // Convert generic string like 'Apr 16, 2026' to Aladhan format 'DD-MM-YYYY'
    let urlExt = '';
    if (dateStr && dateStr !== 'Unknown') {
      const dObj = new Date(dateStr);
      if (!isNaN(dObj)) {
        urlExt = `/${('0' + dObj.getDate()).slice(-2)}-${('0' + (dObj.getMonth() + 1)).slice(-2)}-${dObj.getFullYear()}`;
      }
    }

    fetch(`https://api.aladhan.com/v1/timingsByCity${urlExt}?city=${encodeURIComponent(destination)}&country=&method=2`)
      .then(res => res.json())
      .then(data => {
        if (alive && data?.data) {
          const fmt = (t) => {
            let [h, m] = t.split(':');
            let ampm = h >= 12 ? 'PM' : 'AM';
            h = h % 12 || 12;
            return `${h}:${m} ${ampm}`;
          };

          setTimes({
            Fajr: fmt(data.data.timings.Fajr),
            Sunrise: fmt(data.data.timings.Sunrise),
            Dhuhr: fmt(data.data.timings.Dhuhr),
            Asr: fmt(data.data.timings.Asr),
            Maghrib: fmt(data.data.timings.Maghrib),
            Isha: fmt(data.data.timings.Isha)
          });
          const hd = data.data.date.hijri;
          setHijriDate(`${hd.day} ${hd.month.en} ${hd.year} AH`);
        } else if (alive) {
          setTimes({ error: true });
        }
      })
      .catch(() => {
        if (alive) setTimes({ error: true });
      });
    return () => { alive = false; };
  }, [destination, dateStr]);

  return (
    <AccordionWidget title="Islamic Prayer Times" icon={Moon} iconColor="#38BDF8" defaultOpen={true}>
      <div className="pt-3 pb-1">
        <div className="bg-[#10B981] text-white p-4 rounded-t-xl relative overflow-hidden shadow-inner" style={{ background: 'linear-gradient(135deg, #10B981 0%, #059669 100%)' }}>
          <div className="flex items-center gap-2 mb-2 relative z-10">
            <Moon size={14} className="text-white/90" />
            <p className="text-[11px] font-black uppercase tracking-widest text-[#fff]/90">PRAYER TIMES</p>
          </div>
          <p className="text-[13px] text-white font-medium relative z-10">{hijriDate || 'Calculating...'}</p>
          <p className="text-[11px] text-white/70 mt-1 relative z-10">{destination}</p>
          <Moon size={100} className="absolute -right-6 -bottom-6 text-white/5" strokeWidth={1} />
        </div>
        <div className="space-y-0 text-white font-medium text-[13px] bg-[#0A0F18] px-4 py-1 border border-white/5 border-t-0 shadow-inner">
          {times ? (
            times.error ? (
              <div className="py-8 text-center text-xs text-white/40">Timings unavailable for this location.</div>
            ) : (
              <>
                <div className="flex justify-between items-center py-3 border-b border-white/[0.04]"><span className="flex items-center gap-3"><div className="w-1.5 h-1.5 rounded-full bg-[#818CF8] shrink-0" /><Moon size={14} className="text-white/40" /> Fajr</span> <span className="font-bold">{times.Fajr}</span></div>
                <div className="flex justify-between items-center py-3 border-b border-white/[0.04]"><span className="flex items-center gap-3 text-white/90"><div className="w-1.5 h-1.5 rounded-full bg-[#B45309] shrink-0" /><Sun size={14} className="text-white/65" /> Sunrise</span> <span className="font-bold text-white/95">{times.Sunrise}</span></div>
                <div className="flex justify-between items-center py-3 border-b border-white/[0.04]"><span className="flex items-center gap-3"><div className="w-1.5 h-1.5 rounded-full bg-[#FBBF24] shrink-0" /><Sun size={14} className="text-white/40" /> Dhuhr</span> <span className="font-bold">{times.Dhuhr}</span></div>
                <div className="flex justify-between items-center py-3 border-b border-white/[0.04]"><span className="flex items-center gap-3"><div className="w-1.5 h-1.5 rounded-full bg-[#FB923C] shrink-0" /><Sun size={14} className="text-white/40" /> Asr</span> <span className="font-bold">{times.Asr}</span></div>
                <div className="flex justify-between items-center py-3 border-b border-white/[0.04]"><span className="flex items-center gap-3"><div className="w-1.5 h-1.5 rounded-full bg-[#F87171] shrink-0" /><Sunset size={14} className="text-white/40" /> Maghrib</span> <span className="font-bold">{times.Maghrib}</span></div>
                <div className="flex justify-between items-center py-3"><span className="flex items-center gap-3"><div className="w-1.5 h-1.5 rounded-full bg-[#8B5CF6] shrink-0" /><Moon size={14} className="text-white/40" /> Isha</span> <span className="font-bold">{times.Isha}</span></div>
              </>
            )
          ) : (
            <div className="py-8 text-center text-xs text-white/30">Loading timings...</div>
          )}
        </div>

        {/* Footer Pill */}
        <div className="bg-[#0A0F18] border border-white/5 rounded-b-xl flex justify-between items-center px-4 py-3">
          <span onClick={onPrev} className={`text-[12px] select-none p-1 transition-colors ${onPrev ? 'text-white/40 hover:text-white cursor-pointer' : 'text-white/10 cursor-not-allowed'}`}>{'<'}</span>
          <span className="text-[11px] font-bold text-white/40 tracking-wider">Day {dayIdx} - {dateStr}</span>
          <span onClick={onNext} className={`text-[12px] select-none p-1 transition-colors ${onNext ? 'text-white/40 hover:text-white cursor-pointer' : 'text-white/10 cursor-not-allowed'}`}>{'>'}</span>
        </div>
      </div>
    </AccordionWidget>
  );
}

