/** Stability & Flow helpers */
export const getDays = (y, m) => {
  const firstDay = new Date(y, m, 1).getDay();
  const daysInMonth = new Date(y, m + 1, 0).getDate();
  const prevMonthDays = new Date(y, m, 0).getDate();
  const days = [];
  for (let i = firstDay - 1; i >= 0; i--) days.push({ day: prevMonthDays - i, month: m - 1, year: y, current: false });
  for (let i = 1; i <= daysInMonth; i++) days.push({ day: i, month: m, year: y, current: true });
  const remaining = 42 - days.length;
  for (let i = 1; i <= remaining; i++) days.push({ day: i, month: m + 1, year: y, current: false });
  return days;
};

export const isDisabled = (d, m, y) => {
  const cur = new Date(y, m, d);
  const today = new Date(); today.setHours(0, 0, 0, 0);
  return cur < today;
};

export const CalendarGrid = ({ y, m, start, end, hoverDate, onDayClick, onHover, dateLabel = "Departure" }) => {
  const MONTH_NAMES = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
  const WEEK_DAYS = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];

  const isSelected = (d, m, y) => {
    const cur = new Date(y, m, d); cur.setHours(0, 0, 0, 0);
    const currentTime = cur.getTime();
    const s = start ? new Date(start) : null; if (s) s.setHours(0, 0, 0, 0);
    const e = end ? new Date(end) : null; if (e) e.setHours(0, 0, 0, 0);
    const h = hoverDate ? new Date(hoverDate) : null; if (h) h.setHours(0, 0, 0, 0);
    const startTime = s ? s.getTime() : null;
    const endTime = e ? e.getTime() : null;
    const hoverTime = h ? h.getTime() : null;
    if (startTime && currentTime === startTime) return 'start';
    if (endTime && currentTime === endTime) return 'end';
    if (startTime && endTime && currentTime > startTime && currentTime < endTime) return 'in-range';
    if (startTime && !endTime && hoverTime && (
      (hoverTime > startTime && currentTime > startTime && currentTime <= hoverTime) ||
      (hoverTime < startTime && currentTime < startTime && currentTime >= hoverTime)
    )) return 'in-range-hover';
    return null;
  };

  return (
    <div className="relative z-10 px-2 pt-12 pb-2 min-w-[240px]">
      <div className="flex items-center justify-between mb-3 px-1">
        <h4 className="pr-14 text-white font-display font-black uppercase tracking-[0.18em] text-[10px] sm:text-[11px]">
          {MONTH_NAMES[m]} <span className="text-[#D4AF37]">{y}</span>
        </h4>
      </div>
      <div className="grid grid-cols-7 gap-0.5">
        {WEEK_DAYS.map(d => (
          <div key={d} className="text-center text-[9px] font-black text-white/30 uppercase py-1 tracking-[0.18em]">{d}</div>
        ))}
        {getDays(y, m).map((item, i) => {
          const state = isSelected(item.day, item.month, item.year);
          const disabled = isDisabled(item.day, item.month, item.year);
          const isToday = new Date().toDateString() === new Date(item.year, item.month, item.day).toDateString();
          return (
            <div
              key={i}
              onClick={() => onDayClick(item.day, item.month, item.year)}
              onMouseEnter={() => !disabled && onHover(new Date(item.year, item.month, item.day))}
              onMouseLeave={() => onHover(null)}
              className={cn(
                "relative h-8 w-8 sm:h-[34px] sm:w-[34px] flex items-center justify-center rounded-xl cursor-pointer transition-all duration-300 text-[11px] sm:text-[12px] font-black",
                item.current ? "text-white" : "opacity-0 pointer-events-none",
                disabled && "opacity-10 cursor-not-allowed",
                state === 'start' && "bg-[#D4AF37] text-black shadow-[0_0_20px_rgba(212,175,55,0.4)] z-10 scale-105",
                state === 'end' && "bg-black text-white ring-2 ring-[#D4AF37] shadow-[0_0_20px_rgba(212,175,55,0.3)] z-10 scale-105",
                state === 'in-range' && "bg-[#D4AF37]/30 text-white rounded-none shadow-inner",
                state === 'in-range-hover' && "bg-[#D4AF37]/20 text-white/60 rounded-none",
                !state && item.current && !disabled && "hover:bg-white/10 hover:scale-110",
                isToday && !state && "ring-1 ring-[#D4AF37]/30"
              )}
            >
              {item.day}
              {item.current && state === 'start' && (
                <div className="absolute -top-9 left-1/2 -translate-x-1/2 px-2.5 py-1 bg-[#D4AF37] text-black text-[9px] font-black uppercase rounded-md whitespace-nowrap z-50 shadow-xl pointer-events-none tracking-[0.14em] opacity-100 transition-all">
                  {dateLabel}
                  <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2.5 h-2.5 bg-[#D4AF37] rotate-45" />
                </div>
              )}
              {item.current && state === 'end' && (
                <div className="absolute -top-9 left-1/2 -translate-x-1/2 px-2.5 py-1 bg-[#D4AF37] text-black text-[9px] font-black uppercase rounded-md whitespace-nowrap z-50 shadow-xl pointer-events-none tracking-[0.14em] opacity-100 transition-all">
                  Return
                  <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2.5 h-2.5 bg-[#D4AF37] rotate-45" />
                </div>
              )}
              {state === 'start' && (
                <div className="absolute -top-1 -right-1 w-3.5 h-3.5 rounded-full bg-white border border-black flex items-center justify-center shadow-md z-20 scale-75">
                  <div className="w-1.5 h-1.5 rounded-full bg-[#D4AF37]" />
                </div>
              )}
              {state === 'end' && (
                <div className="absolute -top-1 -right-1 w-3.5 h-3.5 rounded-full bg-[#D4AF37] border border-black flex items-center justify-center shadow-md z-20 scale-75">
                  <Check className="w-2 h-2 text-black font-black" />
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export const CustomCalendar = ({ startDate, endDate, onRangeSelect, numDays }) => {
  const start = useMemo(() => parseLocal(startDate), [startDate]);
  const end = useMemo(() => parseLocal(endDate), [endDate]);
  const [viewDate, setViewDate] = useState(new Date(start || new Date()));
  const [hoverDate, setHoverDate] = useState(null);

  const leftYear = viewDate.getFullYear();
  const leftMonth = viewDate.getMonth();
  const rightDate = new Date(leftYear, leftMonth + 1, 1);
  const rightYear = rightDate.getFullYear();
  const rightMonth = rightDate.getMonth();

  const handleDayClickLocal = (d, m, y) => {
    if (isDisabled(d, m, y)) return;
    const clicked = new Date(y, m, d);
    clicked.setHours(0, 0, 0, 0);
    const clickedTime = clicked.getTime();
    const startTime = start ? start.getTime() : null;
    const endTime = end ? end.getTime() : null;

    if (!start) {
      onRangeSelect(clicked, null);
    } else if (clickedTime === startTime) {
      onRangeSelect(null, null); // Reset all if clicking start again
    } else if (endTime && clickedTime === endTime) {
      onRangeSelect(start, null); // Undo ONLY return if clicking it again
    } else if (clickedTime < startTime) {
      onRangeSelect(clicked, null); // New start if clicking earlier
    } else {
      onRangeSelect(start, clicked); // Set or move return date
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 relative z-10 w-full max-w-[840px] mx-auto items-stretch">
      <div
        className="min-h-[360px] p-4 sm:p-5 rounded-[28px] border border-white/10 shadow-2xl relative overflow-hidden group/dep flex flex-col"
        style={{ background: 'rgba(4,12,28,0.75)', backdropFilter: 'blur(40px)', boxShadow: 'inset 0 0 40px rgba(212,175,55,0.05)' }}
      >
        <div className="absolute inset-0 bg-gradient-to-br from-[#D4AF37]/10 via-transparent to-transparent opacity-20" />
        <button onClick={() => setViewDate(new Date(leftYear, leftMonth - 1, 1))} className="absolute left-4 top-4 w-10 h-10 flex items-center justify-center rounded-full bg-black/65 border border-white/10 hover:border-[#D4AF37]/50 text-white/40 hover:text-[#D4AF37] transition-all z-20 shadow-xl backdrop-blur-xl group/btn active:scale-90">
          <ChevronLeft className="w-4 h-4 group-hover/btn:-translate-x-0.5 transition-transform" />
        </button>
        <div className="relative z-10 flex flex-col items-center h-full">
          <CalendarGrid y={leftYear} m={leftMonth} start={start} end={end} hoverDate={hoverDate} onDayClick={handleDayClickLocal} onHover={setHoverDate} />
          <div className="w-full mt-auto pt-5 border-t border-white/5 flex items-center justify-between px-2">
            <div className="space-y-1 text-left">
              <p className="text-[8px] font-black text-[#D4AF37] uppercase tracking-[0.4em]">From</p>
              <p className="text-base sm:text-lg font-display font-black text-white leading-none">{start ? start.toLocaleDateString('en-US', { month: 'long', day: 'numeric' }) : '---'}</p>
            </div>
            <Users className="w-4 h-4 text-white/10" />
          </div>
        </div>
      </div>

      <div
        className="min-h-[360px] p-4 sm:p-5 rounded-[28px] border border-white/10 shadow-2xl relative overflow-hidden group/ret flex flex-col"
        style={{ background: 'rgba(4,12,28,0.75)', backdropFilter: 'blur(40px)', boxShadow: 'inset 0 0 40px rgba(212,175,55,0.05)' }}
      >
        <div className="absolute inset-0 bg-gradient-to-br from-transparent via-transparent to-[#D4AF37]/10 opacity-20" />
        <button onClick={() => setViewDate(new Date(leftYear, leftMonth + 1, 1))} className="absolute right-4 top-4 w-10 h-10 flex items-center justify-center rounded-full bg-black/65 border border-white/10 hover:border-[#D4AF37]/50 text-white/40 hover:text-[#D4AF37] transition-all z-20 shadow-xl backdrop-blur-xl group/btn active:scale-90">
          <ChevronRight className="w-4 h-4 group-hover/btn:translate-x-0.5 transition-transform" />
        </button>
        <div className="relative z-10 flex flex-col items-center h-full">
          <CalendarGrid y={rightYear} m={rightMonth} start={start} end={end} hoverDate={hoverDate} onDayClick={handleDayClickLocal} onHover={setHoverDate} />
          <div className="w-full mt-auto pt-5 border-t border-white/5 flex items-center justify-between px-2">
            <div className="space-y-1 text-left">
              <p className="text-[8px] font-black text-[#D4AF37] uppercase tracking-[0.4em]">To</p>
              <p className="text-base sm:text-lg font-display font-black text-white leading-none">{end ? end.toLocaleDateString('en-US', { month: 'long', day: 'numeric' }) : '---'}</p>
            </div>
            <div className="px-3 py-1.5 rounded-lg bg-white/[0.03] border border-white/5 flex items-center gap-2">
              <p className="text-[10px] font-black text-white/90 uppercase tracking-[0.2em]">{numDays()} Nights</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

