const BoutiqueSelect = ({ value, options, onChange, label }) => {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const click = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", click);
    return () => document.removeEventListener("mousedown", click);
  }, []);

  return (
    <div className="relative w-full" ref={ref}>
      <button
        onClick={() => setOpen(!open)}
        className="w-full bg-white/5 border border-white/10 rounded-[20px] p-6 text-white font-bold text-xl flex items-center justify-between hover:border-[#D4AF37]/40 transition-all shadow-2xl backdrop-blur-3xl group/sel"
      >
        <span className="truncate drop-shadow-lg">{options[value] || value}</span>
        <ChevronDown className={cn("w-5 h-5 text-[#D4AF37] transition-transform duration-500", open && "rotate-180")} />
      </button>
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, y: 10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.95 }}
            onWheel={(e) => e.stopPropagation()}
            className="absolute top-full left-0 right-0 mt-3 p-3 rounded-2xl bg-[#0a0f1d] border border-white/20 shadow-[0_30px_90px_rgba(0,0,0,0.9)] backdrop-blur-3xl z-[9999] max-h-[280px] overflow-y-auto custom-scrollbar"
            style={{
              scrollbarWidth: 'thin',
              scrollbarColor: '#D4AF37 transparent'
            }}
          >
            <style>{`
              .custom-scrollbar::-webkit-scrollbar { width: 4px; }
              .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
              .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(212,175,55,0.4); border-radius: 10px; }
              .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(212,175,55,0.8); }
            `}</style>
            {Object.entries(options).map(([k, v]) => (
              <button
                key={k}
                onClick={() => { onChange(k); setOpen(false); }}
                className={cn(
                  "w-full text-left px-5 py-4 rounded-xl text-base font-bold transition-all flex items-center justify-between group/opt my-1",
                  value === k ? "bg-[#D4AF37] text-black shadow-[0_0_20px_rgba(212,175,55,0.4)]" : "text-white/90 hover:bg-white/10 hover:text-white"
                )}
              >
                <span className="drop-shadow-md">{v}</span>
                {value === k && <Check className="w-5 h-5" />}
              </button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};



