function getFallbackDistricts(destination) {
  const key = String(destination || '').toLowerCase();
  const match = Object.keys(FALLBACK_DISTRICTS).find((name) => name !== 'default' && key.includes(name));
  return FALLBACK_DISTRICTS[match] || FALLBACK_DISTRICTS.default;
}

function buildVariantActivity(category, variantIndex, fd) {
  const destination = fd.destination || 'this destination';
  const districts = getFallbackDistricts(destination);
  const district = districts[variantIndex % districts.length];
  const styleProfile = getStyleTravelProfile(fd.travelStyle);
  const variantPool = styleProfile.slotLabels?.[category] || FALLBACK_SLOT_VARIANTS[category];
  const variantLabel = variantPool?.[variantIndex % variantPool.length] || FALLBACK_SLOT_VARIANTS[category]?.[variantIndex % FALLBACK_SLOT_VARIANTS[category].length] || 'Curated Stop';
  const theme = buildStyleAwareDayTheme(fd.travelStyle, variantIndex + 1, Math.max(4, Number(fd.totalDaysHint || 8)));
  const style = fd.travelStyle || 'balanced';
  const phase = getTripPhase(variantIndex + 1, Math.max(4, Number(fd.totalDaysHint || 8)));
  const resolvedPlace = resolvePlannedPlaceName("", destination, category, variantIndex);
  const slotNarratives = {
    morning: [
      `Start in ${district} with a gentler introduction to ${destination}, keeping the first stop easy to enter and rewarding on foot.`,
      `Use ${district} as a calm opening chapter in ${destination}, with space to notice architecture, people, and slower local rhythm.`,
      `Begin around ${district} in ${destination} while the city still feels fresh and easier to navigate.`
    ],
    afternoon: [
      `Move into ${district} for a fuller midday experience in ${destination}, where culture, lunch, and walkable discoveries work well together.`,
      `Use the afternoon to settle deeper into ${district}, balancing one stronger stop with nearby local texture in ${destination}.`,
      `Anchor the middle of the day in ${district} so ${destination} feels more lived-in and less rushed.`
    ],
    evening: [
      `Let ${district} carry the golden-hour mood in ${destination}, with softer light and a more scenic pace.`,
      `Shift toward ${district} as ${destination} eases into evening, giving this stop a stronger atmosphere and better photo moments.`,
      `Use ${district} for the transition into dusk so ${destination} feels more cinematic and less crowded.`
    ],
    night: [
      `Close the day through ${district}, where ${destination} feels calmer, more intimate, and easier to enjoy without rushing.`,
      `Keep the final stretch in ${district} relaxed, using it as a softer night close to your time in ${destination}.`,
      `End around ${district} so ${destination} finishes with comfort, ambience, and a lighter late-night pace.`
    ]
  };
  const styleClosers = {
    luxury: ` Shape it like a ${phase === 'finale' ? 'grand closing' : 'premium'} chapter, with comfort and atmosphere doing most of the work.`,
    cultural: ` Treat it as part of a deeper story-led route through ${destination}, not just an isolated stop.`,
    adventure: ` Keep the rhythm active enough to feel like forward motion, but leave recovery space for the rest of the trip.`,
    cinematic: ` Give the light, framing, and atmosphere enough time to matter here.`,
    urban: ` Let one district reveal multiple layers before moving on again.`,
    wellness: ` Keep the pacing restorative and spacious rather than trying to maximize coverage.`,
    halal: ` Keep the flow comfortable, respectful, and easy to navigate around practical needs.`,
    coastal: ` Let the water, breeze, or open-air edge shape the rhythm rather than forcing the pace.`,
  };
  const desc = slotNarratives[category]?.[variantIndex % slotNarratives[category].length] || `Explore ${district} in ${destination}.`;
  const placeName = resolvedPlace && resolvedPlace !== destination ? resolvedPlace : `${district} ${variantLabel}`;

  return {
    name: placeName,
    desc: `${desc} Focus this chapter around ${placeName} so the day feels grounded in a real local anchor, not a generic stop. This stop is tuned for your ${style} travel style and supports the day's ${theme.toLowerCase()} mood with a more distinct local angle.${styleClosers[String(style).toLowerCase()] || ''}`,
    id: null,
  };
}

function buildExpandedActivityPool(items, category, needed, fd) {
  return Array.from({ length: needed }, (_, index) => buildVariantActivity(category, index, fd));
}

function buildItinerary(fd) {
  const daysNum = getInclusiveDayCount(fd.startDate, fd.endDate);
  fd.totalDaysHint = daysNum;
  const travelers = Math.max(1, Number(fd.travelers || fd.groupSize) || 1);
  const category = typeof fd.budgetCategory === "string"
    ? fd.budgetCategory
      : typeof fd.budget === "string"
      ? fd.budget
      : "moderate";
  const budgetSummary = buildBudgetSummary(fd.destination, daysNum, category, travelers, fd.currency || "USD", fd.budget);
  const dayBudgetProfiles = buildDayBudgetProfiles(daysNum, fd.destination, fd.travelStyle);
  const dayAllocationWeights = dayBudgetProfiles.map((profile, index) => {
    const slotAverage = (profile.slotWeights || []).reduce((sum, weight) => sum + (Number(weight) || 0), 0) / Math.max(1, profile.slotWeights?.length || 0);
    const phaseBias = 1 + (((index % 3) - 1) * 0.12) + (index === 0 ? -0.08 : 0) + (index === dayBudgetProfiles.length - 1 ? 0.16 : 0);
    return Math.max(1, (profile.stayWeight + profile.foodWeight + profile.transportWeight + profile.activityWeight + slotAverage) * phaseBias);
  });
  const dayTotals = splitDistinctByWeights(
    budgetSummary.costBreakdown.total,
    dayAllocationWeights,
    `${fd.destination}|${fd.travelStyle}|days`,
    { gapUnit: Math.max(45, Math.floor((budgetSummary.costBreakdown.total || 0) / Math.max(18, daysNum * 12))) }
  );
  const categoryNeeds = { morning: daysNum * 2, afternoon: daysNum * 2, evening: daysNum * 2, night: daysNum * 2 };
  const categoryPools = {
    morning: buildExpandedActivityPool([], 'morning', categoryNeeds.morning, fd),
    afternoon: buildExpandedActivityPool([], 'afternoon', categoryNeeds.afternoon, fd),
    evening: buildExpandedActivityPool([], 'evening', categoryNeeds.evening, fd),
    night: buildExpandedActivityPool([], 'night', categoryNeeds.night, fd),
  };
  const categoryCursors = { morning: 0, afternoon: 0, evening: 0, night: 0 };

  const dayPlans = Array.from({ length: daysNum }, (_, i) => {
    const dNum = i + 1;
    const date = new Date(fd.startDate);
    date.setDate(date.getDate() + i);
    const dateStr = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    const dayTheme = buildStyleAwareDayTheme(fd.travelStyle, dNum, daysNum) || FALLBACK_DAY_THEMES[(dNum - 1) % FALLBACK_DAY_THEMES.length] || `Day ${dNum} - ${fd.destination}`;
    const dayBudgetProfile = dayBudgetProfiles[i] || buildDayBudgetProfile(dayTheme, i, daysNum, fd.destination, fd.travelStyle);

    const getAct = (slot) => {
      const pool = categoryPools[slot] || [];
      const cursor = categoryCursors[slot] || 0;
      const act = pool[cursor] || buildVariantActivity(slot, cursor, fd);
      categoryCursors[slot] = cursor + 1;
      return act;
    };

    const fullSlotsList = ['morning', 'morningActivity', 'afternoon', 'afternoonActivity', 'evening', 'eveningActivity', 'night', 'nightActivity'];
    const baseCat = ['morning', 'morning', 'afternoon', 'afternoon', 'evening', 'evening', 'night', 'night'];
    const [dayStayBudget, dayFoodBudget, dayTransportBudget, dayActivitiesBudget] = splitByWeights(
      dayTotals[i] || 0,
      [
        budgetSummary.costBreakdown.stay * dayBudgetProfile.stayWeight,
        budgetSummary.costBreakdown.food * dayBudgetProfile.foodWeight,
        budgetSummary.costBreakdown.transport * dayBudgetProfile.transportWeight,
        budgetSummary.costBreakdown.activities * dayBudgetProfile.activityWeight,
      ]
    );
    const slotEntries = fullSlotsList.map((slotKey, si) => {
      const slot = baseCat[si];
      const act = getAct(slot);
      const knownId = act.id && act.id.length >= 10 && !act.id.includes(' ');
      const fallbackContent = generatePlaceCardFallbackContent(act.name, act.desc, fd.destination, slotKey, {
        travelStyle: fd.travelStyle,
        dayNumber: dNum,
        totalDays: daysNum,
        dayTheme,
      });
      const transferMinutes = 14 + ((dNum * 11 + si * 7) % 18);
      return {
        slotKey,
        payload: {
        place: act.name,
        activity: act.desc,
        image: act.id || act.name,
        imageQuery: _extractLocationQuery(act.name, fd.destination),
        knownId,
        travel: `about ${transferMinutes} min from the previous stop`,
        duration: slot === 'night' ? '1-2h' : slot === 'morning' ? '3h' : '2-3h',
        reason: `Best suited for ${slot === 'morning' ? 'an energetic start' : slot === 'evening' ? 'a scenic wind-down' : slot === 'night' ? 'an intimate close' : 'full afternoon immersion'} - aligns with your ${fd.travelStyle || 'travel'} style${fd.preferences?.length ? ` and ${fd.preferences[si % fd.preferences.length]} preference.` : '.'}`,
        timePlan: fallbackContent.schedule,
        streetFinds: fallbackContent.streetFinds,
        nearbyHighlights: fallbackContent.streetFinds.slice(0, 3),
        exploreIdeas: fallbackContent.ideas,
        transportationTip: `Keep transfers around ${transferMinutes} minutes to protect the day's pacing.`,
        culturalInsight: `This ${slot.replace(/Activity/, ' activity')} stop works best when treated as part of the wider ${dayTheme.toLowerCase()} flow.`,
        },
        act,
      };
    });
    const slotCosts = splitDistinctByWeights(
      dayTotals[i] || 0,
      buildPlanSlotWeights(slotEntries.map(({ slotKey, act }) => ({ slotKey, act }))),
      `${fd.destination}|${dNum}|slots`,
      { gapUnit: Math.max(10, Math.floor((dayTotals[i] || 0) / 140)) }
    );
    const slots = slotEntries.reduce((acc, { slotKey, payload }, si) => {
      acc[slotKey] = {
        ...payload,
        cost: slotCosts[si] || 0,
      };
      return acc;
    }, {});

    const dailyBudget = {
      stay: dayStayBudget || 0,
      food: dayFoodBudget || 0,
      transport: dayTransportBudget || 0,
      activities: dayActivitiesBudget || 0,
      total: dayTotals[i] || 0
    };

    return {
      day: dNum,
      date: dateStr,
      theme: dayTheme,
      ...slots,
      budget: dailyBudget
    };
  });

  const total_budget = {
    ...budgetSummary.costBreakdown,
  };

  return {
    trip_overview: {
      destination: fd.destination,
      dates: `${new Date(fd.startDate).toLocaleDateString()} - ${new Date(fd.endDate).toLocaleDateString()}`,
      total_days: daysNum,
      budget: fmtCur(total_budget.total, fd.currency),
      travel_style: fd.travelStyle,
      passengers: travelers,
      currency: fd.currency,
    },
    days: dayPlans,
    total_budget,
    ai_suggestions: {
      hidden_gems: ['Serene Coastal Path', 'Artisan Quarter Alleyways', 'Historic Library Cafe'],
      photo_spots: ['The Golden Gateway', 'Reflections Fountain', 'Rooftop Perspective'],
      tips: ['Early arrival optimizes the experience nodes.', 'Pre-book connectivity segments for smooth transitions.'],
      avoid: ['Midday peak exposure in central squares', 'Unverified secondary transport links']
    }
  };
}
function getDestinationImage(dest) {
  const key = Object.keys(GALLERY).find(k => dest.toLowerCase().includes(k.toLowerCase())) || "default";
  const imgs = GALLERY[key];
  return imgs[0]; // Return the primary ID
}


