const getCountry = (destination) => {
  if (!destination) return "global";
  const key = destination.toLowerCase();
  const found = Object.keys(placeToCountryMap).find(k => key.includes(k));
  return placeToCountryMap[found] || "global";
};

const getAutoCurrency = (destination) => {
  const country = getCountry(destination);
  return countryToCurrency[country] || "USD";
};

// Currency conversion rates (base: INR)
const currencyRates = {
  INR: 1, USD: 0.012, EUR: 0.011, GBP: 0.0095,
  AED: 0.044, JPY: 1.8, THB: 0.44, IDR: 0.000077,
  CAD: 0.016, AUD: 0.018, SGD: 0.016, CHF: 0.011,
  MYR: 0.057, TRY: 0.39, KWD: 0.0037, QAR: 0.044,
  SAR: 0.045, OMR: 0.0046, CNY: 0.087,
};

const convertCurrency = (amountINR, currency) => {
  const rate = currencyRates[currency] ?? 1;
  return Math.round(amountINR * rate);
};

