const BUDGET_CATEGORY_MULTIPLIERS = {
  budget: 0.46,
  moderate: 1,
  premium: 1.55,
  luxury: 2.35,
};

const BUDGET_SPLIT_RATIOS = {
  budget: { stay: 0.34, food: 0.25, transport: 0.12, activities: 0.29 },
  moderate: { stay: 0.38, food: 0.24, transport: 0.1, activities: 0.28 },
  premium: { stay: 0.43, food: 0.22, transport: 0.09, activities: 0.26 },
  luxury: { stay: 0.5, food: 0.18, transport: 0.08, activities: 0.24 },
};

const getDestinationBudgetProfile = (destination, category) => {
  const country = getCountry(destination);
  const key = String(destination || "").toLowerCase();
  const matchedPlace = Object.keys(PLACE_BUDGET_ADJUSTMENTS).find((place) => key.includes(place));
  const placeFactor = matchedPlace ? PLACE_BUDGET_ADJUSTMENTS[matchedPlace] : 1;
  const categoryKey = DESTINATION_BUDGET_PROFILES[country]?.[category] ? category : "moderate";
  const baseProfile = DESTINATION_BUDGET_PROFILES[country]?.[categoryKey] || DESTINATION_BUDGET_PROFILES.global[categoryKey];

  return {
    stay: Math.round(baseProfile.stay * placeFactor),
    food: Math.round(baseProfile.food * placeFactor),
    local: Math.round(baseProfile.local * placeFactor),
    misc: Math.round(baseProfile.misc * placeFactor),
  };
};

const getDestinationDailyBenchmarkINR = (destination) => {
  const country = getCountry(destination);
  const key = String(destination || "").toLowerCase();
  const matchedPlace = Object.keys(PLACE_DAILY_BENCHMARKS_INR).find((place) => key.includes(place));
  if (matchedPlace) return PLACE_DAILY_BENCHMARKS_INR[matchedPlace];
  return DAILY_BENCHMARKS_INR[country] || DAILY_BENCHMARKS_INR.global;
};

const getSharedStayDiscount = (groupSize, category) => {
  if (groupSize <= 1) return 1;
  if (category === "luxury") {
    if (groupSize === 2) return 0.97;
    if (groupSize === 3) return 0.93;
    if (groupSize === 4) return 0.9;
    return Math.max(0.84, 0.9 - (groupSize - 4) * 0.02);
  }
  if (groupSize === 2) return 0.9;
  if (groupSize === 3) return 0.82;
  if (groupSize === 4) return 0.76;
  return Math.max(0.68, 0.76 - (groupSize - 4) * 0.02);
};

const getSharedTransportDiscount = (groupSize) => {
  if (groupSize <= 1) return 1;
  if (groupSize === 2) return 0.92;
  if (groupSize === 3) return 0.86;
  if (groupSize === 4) return 0.82;
  return Math.max(0.72, 0.82 - (groupSize - 4) * 0.02);
};

const calculateBudget = (destination, days, category = "moderate", groupSize = 1) => {
  const safeDays = Math.max(1, Number(days) || 1);
  const safeGroup = Math.max(1, Number(groupSize) || 1);
  const categoryKey = BUDGET_CATEGORY_META[category] ? category : "moderate";
  const dailyBenchmark = getDestinationDailyBenchmarkINR(destination);
  const multiplier = BUDGET_CATEGORY_MULTIPLIERS[categoryKey] || 1;
  const ratios = BUDGET_SPLIT_RATIOS[categoryKey] || BUDGET_SPLIT_RATIOS.moderate;

  const tripLengthFactor = safeDays >= 10 ? 0.9 : safeDays >= 6 ? 0.95 : safeDays >= 4 ? 0.98 : 1;
  const baseTotalINR = dailyBenchmark * multiplier * safeDays * safeGroup * tripLengthFactor;
  const stayINR = Math.round(baseTotalINR * ratios.stay * getSharedStayDiscount(safeGroup, categoryKey));
  const foodINR = Math.round(baseTotalINR * ratios.food);
  const transportINR = Math.round(baseTotalINR * ratios.transport * getSharedTransportDiscount(safeGroup));
  const activitiesINR = Math.round(baseTotalINR * ratios.activities);
  const totalINR = stayINR + foodINR + transportINR + activitiesINR;
  const dailyINR = Math.round(totalINR / safeDays);

  return {
    dailyINR,
    foodINR,
    stayINR,
    transportINR,
    activitiesINR,
    otherINR: transportINR + activitiesINR,
    totalINR,
  };
};

const splitEvenly = (total, parts) => {
  const safeParts = Math.max(1, Number(parts) || 1);
  const safeTotal = Math.max(0, Math.round(Number(total) || 0));
  const base = Math.floor(safeTotal / safeParts);
  let remainder = safeTotal - base * safeParts;

  return Array.from({ length: safeParts }, () => {
    if (remainder > 0) {
      remainder -= 1;
      return base + 1;
    }
    return base;
  });
};

const splitByWeights = (total, weights = []) => {
  const safeTotal = Math.max(0, Math.round(Number(total) || 0));
  const safeWeights = Array.isArray(weights) && weights.length ? weights : [1];
  const totalWeight = safeWeights.reduce((sum, weight) => sum + Math.max(0, Number(weight) || 0), 0) || safeWeights.length;
  const values = safeWeights.map((weight) => Math.floor((safeTotal * (Math.max(0, Number(weight) || 0) || 1)) / totalWeight));
  let remainder = safeTotal - values.reduce((sum, value) => sum + value, 0);

  for (let i = 0; i < values.length && remainder > 0; i += 1) {
    values[i] += 1;
    remainder -= 1;
  }

  return values;
};

const getInclusiveDayCount = (startDate, endDate, fallback = 1) => {
  const start = new Date(startDate);
  const end = new Date(endDate);
  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return fallback;
  return Math.min(30, Math.max(1, Math.ceil((end - start) / 86400000) + 1));
};

const stableBudgetSeed = (value = "") => Array.from(String(value)).reduce((sum, char, index) => {
  return sum + (char.charCodeAt(0) * (index + 1));
}, 0);

const splitDistinctByWeights = (total, weights = [], seed = "", options = {}) => {
  const safeWeights = Array.isArray(weights) && weights.length ? weights : [1];
  const safeTotal = Math.max(0, Math.round(Number(total) || 0));
  const requestedGap = Math.max(1, Number(options.gapUnit) || 1);
  const maxGap = Math.max(1, Math.floor(safeTotal / Math.max(1, (safeWeights.length * (safeWeights.length - 1)) / 2 || 1)));
  const gapUnit = Math.max(1, Math.min(requestedGap, maxGap));
  const distinctFloor = ((safeWeights.length * (safeWeights.length - 1)) / 2) * gapUnit;

  if (safeWeights.length <= 1 || safeTotal < distinctFloor) {
    return splitByWeights(safeTotal, safeWeights);
  }

  const order = safeWeights
    .map((weight, index) => ({
      index,
      weight: Math.max(0, Number(weight) || 0),
      tie: stableBudgetSeed(`${seed}|${index}`),
    }))
    .sort((a, b) => (a.weight - b.weight) || (a.tie - b.tie));

  const offsets = Array.from({ length: safeWeights.length }, () => 0);
  order.forEach(({ index }, rank) => {
    offsets[index] = rank * gapUnit;
  });

  const weightedValues = splitByWeights(safeTotal - distinctFloor, safeWeights);
  return weightedValues.map((value, index) => value + offsets[index]);
};

const buildPlanSlotWeights = (entries = []) => {
  return entries.map(({ slotKey, act }, index) => {
    const seed = stableBudgetSeed(`${slotKey}|${act?.name || act?.place || ""}|${act?.desc || act?.activity || ""}|${index}`);
    const slotBias = {
      morning: 0.92,
      morningActivity: 1.08,
      afternoon: 1.02,
      afternoonActivity: 1.16,
      evening: 1.24,
      eveningActivity: 1.33,
      night: 1.2,
      nightActivity: 1.42,
    }[slotKey] || 1;
    const text = `${act?.name || act?.place || ""} ${act?.desc || act?.activity || ""}`.toLowerCase();
    const premiumBias = /(fine dining|restaurant|lounge|rooftop|harbour|harbor|market city|mall|premium|private|signature|sunset|night|museum|gallery|planetarium|resort)/.test(text) ? 0.18 : 0;
    const scenicBias = /(beach|view|bridge|lighthouse|waterfront|coast|summit|society|cathedral|basilica)/.test(text) ? 0.1 : 0;
    return (1 + ((seed % 9) * 0.11)) * slotBias + premiumBias + scenicBias;
  });
};

const buildDayBudgetProfile = (theme = "", index = 0, totalDays = 1, destination = "", travelStyle = "") => {
  const normalizedTheme = String(theme || "").toLowerCase();
  const style = String(travelStyle || "").toLowerCase();
  const destSeed = Array.from(String(destination || "")).reduce((sum, char) => sum + char.charCodeAt(0), 0);
  const seedDrift = ((destSeed + index * 17) % 9) * 0.02;
  const profile = {
    stayWeight: 1,
    foodWeight: 1,
    transportWeight: 1,
    activityWeight: 1,
    slotWeights: [0.09, 0.16, 0.11, 0.14, 0.13, 0.16, 0.08, 0.13],
  };

  if (/arrival|first impressions/.test(normalizedTheme)) {
    profile.stayWeight += 0.42;
    profile.foodWeight -= 0.08;
    profile.transportWeight += 0.38;
    profile.activityWeight -= 0.26;
    profile.slotWeights = [0.05, 0.12, 0.08, 0.12, 0.11, 0.17, 0.14, 0.21];
  }
  if (/heritage|culture|monument|gallery/.test(normalizedTheme)) {
    profile.foodWeight += 0.04;
    profile.transportWeight -= 0.06;
    profile.activityWeight += 0.32;
    profile.slotWeights = [0.12, 0.17, 0.14, 0.17, 0.12, 0.14, 0.05, 0.09];
  }
  if (/hidden gems|local|markets|flavors|street/.test(normalizedTheme)) {
    profile.foodWeight += 0.22;
    profile.transportWeight += 0.07;
    profile.activityWeight += 0.16;
    profile.slotWeights = [0.08, 0.12, 0.13, 0.16, 0.14, 0.17, 0.08, 0.12];
  }
  if (/coastal|nature|scenic|waterfront|landscape/.test(normalizedTheme)) {
    profile.foodWeight -= 0.04;
    profile.transportWeight += 0.18;
    profile.activityWeight += 0.24;
    profile.slotWeights = [0.11, 0.16, 0.1, 0.15, 0.14, 0.16, 0.07, 0.11];
  }
  if (/sunset|night|after dark|dining|finale|farewell|signature/.test(normalizedTheme)) {
    profile.stayWeight -= 0.06;
    profile.foodWeight += 0.3;
    profile.transportWeight -= 0.02;
    profile.activityWeight += 0.2;
    profile.slotWeights = [0.07, 0.11, 0.09, 0.12, 0.14, 0.18, 0.12, 0.17];
  }

  if (index === 0) {
    profile.transportWeight += 0.12;
    profile.activityWeight -= 0.06;
  }
  if (index === totalDays - 1) {
    profile.foodWeight += 0.12;
    profile.activityWeight += 0.08;
  }

  if (style === "luxury") {
    profile.stayWeight += 0.26;
    profile.foodWeight += 0.11 + (index % 2 === 0 ? 0 : 0.06);
    profile.activityWeight += index % 2 === 0 ? 0.09 : 0.18;
    profile.slotWeights = profile.slotWeights.map((weight, slotIndex) => weight + (slotIndex >= 4 ? 0.015 : 0));
  } else if (style === "adventure") {
    profile.transportWeight += 0.18;
    profile.activityWeight += 0.24;
    profile.slotWeights = profile.slotWeights.map((weight, slotIndex) => weight + (slotIndex <= 3 ? 0.018 : 0.008));
  } else if (style === "relaxation") {
    profile.stayWeight += 0.15;
    profile.foodWeight += 0.09;
    profile.transportWeight -= 0.05;
    profile.slotWeights = profile.slotWeights.map((weight, slotIndex) => weight + (slotIndex >= 4 ? 0.02 : -0.005));
  } else if (style === "nature") {
    profile.transportWeight += 0.12;
    profile.activityWeight += 0.16;
    profile.slotWeights = profile.slotWeights.map((weight, slotIndex) => weight + (slotIndex === 1 || slotIndex === 3 || slotIndex === 5 ? 0.015 : 0));
  }

  profile.stayWeight += seedDrift * 0.9;
  profile.foodWeight += seedDrift * 0.75 + (index % 2 === 1 ? 0.05 : 0);
  profile.transportWeight += seedDrift * 0.55;
  profile.activityWeight += seedDrift * 1.1 + (index % 3 === 1 ? 0.08 : 0);
  profile.slotWeights = profile.slotWeights.map((weight, slotIndex) => Math.max(0.04, Number((weight + (((destSeed + index * 5 + slotIndex * 7) % 5) - 2) * 0.006).toFixed(4))));

  return {
    stayWeight: Math.max(0.7, Number(profile.stayWeight.toFixed(3))),
    foodWeight: Math.max(0.68, Number(profile.foodWeight.toFixed(3))),
    transportWeight: Math.max(0.64, Number(profile.transportWeight.toFixed(3))),
    activityWeight: Math.max(0.62, Number(profile.activityWeight.toFixed(3))),
    slotWeights: profile.slotWeights,
  };
};

const buildDayBudgetProfiles = (days, destination = "", travelStyle = "") => {
  const safeDays = Math.max(1, Number(days) || 1);
  return Array.from({ length: safeDays }, (_, index) => (
    buildDayBudgetProfile(
      FALLBACK_DAY_THEMES[index % FALLBACK_DAY_THEMES.length] || `Day ${index + 1}`,
      index,
      safeDays,
      destination,
      travelStyle,
    )
  ));
};

const buildBudgetSummary = (destination, days, category, travelers = 1, currency = "USD", explicitTotal = 0) => {
  const raw = calculateBudget(destination, days, category, travelers);
  const safeDays = Math.max(1, Number(days) || 1);
  const requestedTotal = Math.max(0, Math.round(Number(explicitTotal) || 0));
  const categoryStay = convertCurrency(raw.stayINR, currency);
  const categoryFood = convertCurrency(raw.foodINR, currency);
  const categoryTransport = convertCurrency(raw.transportINR, currency);
  const categoryActivities = convertCurrency(raw.activitiesINR, currency);
  const categoryTotal = categoryStay + categoryFood + categoryTransport + categoryActivities;
  const total = requestedTotal || categoryTotal;
  const splitSource = categoryTotal > 0
    ? [categoryStay, categoryFood, categoryTransport, categoryActivities]
    : [0.4, 0.24, 0.11, 0.25];
  const [stay, food, transport, activities] = splitByWeights(total, splitSource);

  return {
    daily: Math.round(total / safeDays),
    stay,
    food,
    transport,
    activities,
    other: transport + activities,
    total,
    currency,
    costBreakdown: {
      stay,
      food,
      transport,
      activities,
      total,
      currency,
      source: "planner-budget-engine",
    },
  };
};

const mergePlannerBudgetBreakdown = (primary = {}, plannerBudget = {}, requestedTotal = 0, currency = "USD") => {
  const forcedTotal = Math.max(0, Math.round(Number(requestedTotal) || 0));
  const baseTotal = forcedTotal || Math.max(0, Math.round(Number(primary?.total || plannerBudget?.total) || 0));
  const base = {
    ...plannerBudget,
    ...primary,
    currency: primary?.currency || plannerBudget?.currency || currency,
  };
  const splitSource = [
    Math.max(0, Number(base.stay) || 0),
    Math.max(0, Number(base.food) || 0),
    Math.max(0, Number(base.transport) || 0),
    Math.max(0, Number(base.activities) || 0),
  ];
  const [stay, food, transport, activities] = splitByWeights(
    baseTotal,
    splitSource.some(Boolean) ? splitSource : [0.4, 0.24, 0.11, 0.25]
  );

  return {
    ...base,
    stay,
    food,
    transport,
    activities,
    total: baseTotal,
    currency: base.currency || currency,
    source: "planner-budget-locked",
  };
};


const getAutoCategory = (dailyAmount) => {
  if (dailyAmount < 3500) return "budget";
  if (dailyAmount < 7500) return "moderate";
  if (dailyAmount < 14000) return "premium";
  return "luxury";
};


