¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚ÂÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬
  // Fires whenever the AI result arrives. Fetches destination-accurate,
  // per-slot unique images. Cache key = place+slot so same place at morning
  // vs evening can show different photos.
  useEffect(() => {
    if (!generatedResult?.days?.length) return;
    const SLOTS = ["morning", "morningActivity", "afternoon", "afternoonActivity", "evening", "eveningActivity", "night", "nightActivity"];
    const SLOT_LABEL = {
      morning: 'Morning', morningActivity: 'Activity',
      afternoon: 'Afternoon', afternoonActivity: 'Activity',
      evening: 'Evening', eveningActivity: 'Activity',
      night: 'Night', nightActivity: 'Activity'
    };
    const DEST = (generatedResult.trip_overview?.destination || formData.destination || '').split(',')[0].trim();

    // Rich, slot-aware query: "[Place] [first 4 words of activity] [Morning|Afternoon|ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¦] [Destination]"
    const buildQuery = (act, sk) => {
      const place = (act?.place || '').trim();
      const actWords = (act?.activity || '').split(' ').slice(0, 4).join(' ');
      const timeCtx = SLOT_LABEL[sk] || '';
      return [place, actWords, timeCtx, DEST].filter(Boolean).join(' ');
    };

    // Composite cache key ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â place + slot + idx ensures uniqueness across all days/slots
    const cacheKey = (act, sk, idx) =>
      'rihla_img_v5_' + (act?.place + '_' + sk + '_' + idx).toLowerCase().replace(/[^a-z0-9]/g, '_').slice(0, 120);

    const fetchImage = async (act, sk, idx) => {
      const storageKey = cacheKey(act, sk, idx);
      const hit = sessionStorage.getItem(storageKey);
      if (hit) return { cacheKey: storageKey, url: hit };

      const query = buildQuery(act, sk);
      const queries = _buildPlannerImageQueries({
        place: act?.place,
        activity: act?.activity,
        destination: DEST,
        details: act,
      });
      const url = await _fetchActivityImage(queries.length ? queries : query, idx);
      if (url) sessionStorage.setItem(storageKey, url);
      return { cacheKey: storageKey, url };

      // Tier 1 - Google Places API backend proxy with unique photoIndex per slot
      // photoIndex = global sequential index across ALL days & slots ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â guarantees unique photos
    };

    const run = async () => {
      const tasks = [];
      let idx = 0;
      for (const day of generatedResult.days) {
        for (const sk of SLOTS) {
          const act = day[sk];
          if (!act?.place) continue;
          tasks.push({ act, sk, idx: idx++ });
        }
      }
      const results = await Promise.all(
        tasks.map(({ act, sk, idx }) => fetchImage(act, sk, idx))
      );
      // Rebuild cache using composite key format "place_slot" for lookup in buildSrcs
      const cache = {};
      tasks.forEach(({ act, sk }, i) => {
        const { url } = results[i];
        if (act?.place && url) cache[act.place + '_' + sk] = url;
      });
      setActImgCache(cache);
    };

    run();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [generatedResult]);
