  const numDays = () => {
    if (!formData.startDate || !formData.endDate) return 0;
    const s = new Date(formData.startDate);
    const e = new Date(formData.endDate);
    if (isNaN(s.getTime()) || isNaN(e.getTime())) return 0;
    return getInclusiveDayCount(s, e, 0);
  };

  // Auto-set currency when destination changes
  useEffect(() => {
    if (!formData.destination) return;
    const autoCurrency = getAutoCurrency(formData.destination);
    setFormData(prev => ({ ...prev, currency: autoCurrency }));
  }, [formData.destination]);

  // Ref to prevent loop: set to true when we auto-push budget into formData
  const isAutoSettingBudget = useRef(false);
  const isManualBudgetOverride = useRef(false);

  // AUTO-CALC: fires when destination / dates / category / currency / travelers changes
  useEffect(() => {
    const days = numDays();
    if (!formData.destination || days < 1) return;
    const groupSize = Math.max(1, formData.travelers || 1);
    const summary = buildBudgetSummary(
      formData.destination,
      days,
      budgetCategory,
      groupSize,
      formData.currency,
      isManualBudgetOverride.current ? formData.budget : 0
    );
    setBudgetBreakdown({
      daily: summary.daily,
      food: summary.food,
      stay: summary.stay,
      other: summary.other,
      total: summary.total,
    });
    if (!isManualBudgetOverride.current) {
      isAutoSettingBudget.current = true;
      setFormData(prev => ({ ...prev, budget: summary.total }));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [formData.destination, formData.startDate, formData.endDate, budgetCategory, formData.currency, formData.travelers]);


  // MANUAL OVERRIDE: fires when user types in the budget field
  useEffect(() => {
    if (isAutoSettingBudget.current) { isAutoSettingBudget.current = false; return; }
    const days = numDays();
    if (!formData.budget || days < 1) return;
    const daily = Math.round(formData.budget / days);
    const stay = Math.round(daily * 0.45);
    const food = Math.round(daily * 0.24);
    const other = Math.max(0, daily - stay - food);
    const autoCategory = getAutoCategory(daily);
    if (autoCategory !== budgetCategory) setBudgetCategory(autoCategory);
    setBudgetBreakdown({ daily, food, stay, other, total: formData.budget });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [formData.budget]);


